        r = int(a[0]); c = int(a[1])
    except:
        return False
    h = len(s); w = len(s[0]) if h else 0
    if not (0 <= r < h and 0 <= c < w): return False
    for dr, dc in [(1,0), (-1,0)]:
        for k in range(1, 20+1):
            nr, nc = r + dr*k, c + dc*k
            if not (0 <= nr < h and 0 <= nc < w):
                break
            if s[nr][nc] == rfts.EMPTY:
                return True
    return False

